            //                     "status":"Listed",
            //                     "tipOrderQty":0,
            //                     "listTime":1668225600000,
            //                     "majorSymbol":true,
            //                     "defaultLeverage":"-10",
            //                     "fundingInterval":28800,
            //                     "maxLeverage":100,
            //                     "maxOrderQtyRq":"1000",
            //                     "maxPriceRp":"2000000000",
            //                     "minOrderValueRv":"1",
